"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { Barcode, Download, AlertCircle, Check, Copy } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";

const BARCODE_TYPES = [
  { 
    value: "qrcode", 
    label: "QR Code", 
    example: "https://example.com",
    description: "Links to literature, conference posters, contact exchange, e-payments."
  },
  { 
    value: "ean13", 
    label: "EAN-13 (JAN)", 
    example: "4901234567894",
    description: "Purchase & management of commercial products in Japan."
  },
  { 
    value: "upca", 
    label: "UPC-A", 
    example: "012345678905",
    description: "Management of US software, equipment, or imported goods."
  },
  { 
    value: "code128", 
    label: "CODE 128", 
    example: "LAB-999-XYZ",
    description: "Lab inventory. Alphanumeric support makes it ideal for sample IDs."
  },
  { 
    value: "datamatrix", 
    label: "Data Matrix", 
    example: "SN-2026-X1",
    description: "Micro-object tracking. Microtube bases or tiny electronic parts."
  },
  { 
    value: "isbn", 
    label: "ISBN / ISSN", 
    example: "9784000088275",
    description: "Identification and reference management for books and journals."
  },
];

const COLOR_PRESETS = [
  { name: "Black & White", fg: "#000000", bg: "#ffffff" },
  { name: "Black & Ivory", fg: "#000000", bg: "#f8f7e9" },
  { name: "Light Gray", fg: "#ced0d2", bg: "#f8f7e9" },
  { name: "Blueprint", fg: "#1e3a8a", bg: "#eff6ff" },
  { name: "Sepia", fg: "#432818", bg: "#fefae0" },
];

export default function BarcodePage() {
  const [text, setText] = useState("https://example.com");
  const [barcodeType, setBarcodeType] = useState("qrcode");
  const [fgColor, setFgColor] = useState("#000000");
  const [bgColor, setBgColor] = useState("#ffffff");
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false); // For text copy
  const [pngCopied, setPngCopied] = useState(false); // For image copy

  const canvasRef = useRef<HTMLCanvasElement>(null);

  const getScale = useCallback(() => {
    return 4; // 繧ｵ繧､繧ｺ縺ｯ蟶ｸ縺ｫM (scale 4)
  }, []);

  const generateBarcode = useCallback(async () => {
    if (!canvasRef.current) return;
    setError(null);

    // 蜀・ｮｹ縺檎ｩｺ縺ｮ蝣ｴ蜷医・繧ｭ繝｣繝ｳ繝舌せ繧偵け繝ｪ繧｢縺励※邨ゆｺ・n    if (!text.trim()) {
      const ctx = canvasRef.current.getContext("2d");
      if (ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      return;
    }

    try {
      const bwipjs = (await import("bwip-js")).default;
      const is2D = ["qrcode", "datamatrix"].includes(barcodeType);

      let activeBcid = barcodeType;
      const digitsOnly = text.replace(/[\s-]/g, ""); // 繧ｹ繝壹・繧ｹ繝ｻ繝上う繝輔Φ髯､蜴ｻ
      let finalUpdateText = text;

      // JAN, UPC, ISBN/ISSN 縺ｮ蝣ｴ蜷医・繝上う繝輔Φ謚懊″縺ｧ蜃ｦ逅・n      if (["ean13", "upca", "isbn"].includes(barcodeType)) {
        finalUpdateText = digitsOnly;

        if (barcodeType === "isbn") {
          if (digitsOnly.length === 8) {
            activeBcid = "issn";
          } else if (digitsOnly.length === 13) {
            activeBcid = "ean13";
          } else {
            activeBcid = "isbn";
          }
        }
      }

      const options: any = {
        bcid: activeBcid,
        text: finalUpdateText,
        scale: getScale(),
        includetext: !is2D,
        textxalign: "center",
        backgroundcolor: bgColor.replace("#", ""),
        barcolor: fgColor.replace("#", ""),
        textcolor: fgColor.replace("#", ""),
      };

      if (!is2D) {
        options.height = 15;
      }

      // Canvas rendering
      bwipjs.toCanvas(canvasRef.current, options);

    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      setError(`Generation error: ${msg}`);

      // 繧ｨ繝ｩ繝ｼ譎ゅ・蜿､縺・ヰ繝ｼ繧ｳ繝ｼ繝峨ｒ豸亥悉
      const ctx = canvasRef.current.getContext("2d");
      if (ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  }, [text, barcodeType, getScale, fgColor, bgColor]);

  useEffect(() => {
    const timer = setTimeout(generateBarcode, 300);
    return () => clearTimeout(timer);
  }, [generateBarcode]);
  const handleDownloadPng = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const url = canvas.toDataURL("image/png");
    const a = document.createElement("a");
    a.href = url;
    a.download = `${barcodeType}_${text.slice(0, 10).replace(/[^a-z0-9]/gi, "_")}.png`;
    a.click();
  };

  const handleCopyPng = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    try {
      const blob = await new Promise<Blob | null>(resolve => 
        canvas.toBlob(resolve, 'image/png')
      );
      if (blob) {
        const item = new ClipboardItem({ 'image/png': blob });
        await navigator.clipboard.write([item]);
        setPngCopied(true);
        setTimeout(() => setPngCopied(false), 2000);
      }
    } catch {
      setError("Failed to copy image.");
    }
  };

  const handleDownloadSvg = async () => {
    try {
      const bwipjs = (await import("bwip-js")).default;
      const is2D = ["qrcode", "datamatrix"].includes(barcodeType);

      let activeBcid = barcodeType;
      const digitsOnly = text.replace(/[\s-]/g, "");
      let finalUpdateText = text;

      if (["ean13", "upca", "isbn"].includes(barcodeType)) {
        finalUpdateText = digitsOnly;
        if (barcodeType === "isbn") {
          if (digitsOnly.length === 8) {
            activeBcid = "issn";
          } else if (digitsOnly.length === 13) {
            activeBcid = "ean13";
          } else {
            activeBcid = "isbn";
          }
        }
      }

      const options: any = {
        bcid: activeBcid,
        text: finalUpdateText,
        scale: getScale(),
        includetext: !is2D,
        textxalign: "center",
        backgroundcolor: bgColor.replace("#", ""),
        barcolor: fgColor.replace("#", ""),
        textcolor: fgColor.replace("#", ""),
      };

      if (!is2D) {
        options.height = 15;
      }

      const svg = (bwipjs as any).toSVG(options);

      const blob = new Blob([svg], { type: "image/svg+xml" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `${barcodeType}_${text.slice(0, 10).replace(/[^a-z0-9]/gi, "_")}.svg`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (e) {
      setError("Failed to generate SVG.");
    }
  };

  const copyText = async () => {
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const selectedType = BARCODE_TYPES.find((t) => t.value === barcodeType);

  return (
    <div className="p-4 md:p-6 w-full max-w-[1400px] mx-auto space-y-6">
      <div className="mb-2">
        <h2 className="text-2xl font-extrabold text-white bg-gradient-to-r from-rose-400 to-pink-500 text-transparent bg-clip-text">
          Barcode &amp; QR Generator
        </h2>
        <p className="text-zinc-400 text-sm mt-0.5">
          Generate various formats instantly. Save as SVG/PNG.
        </p>
      </div>
      <Separator className="bg-zinc-800/50" />

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
        {/* Settings - 7 cols */}
        <div className="xl:col-span-7 space-y-6">
          {/* Barcode type grid */}
          <div className="space-y-3">
            <Label className="text-zinc-300 text-xs font-bold uppercase tracking-wider">Select Format</Label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {BARCODE_TYPES.map((t) => (
                <button
                  key={t.value}
                  onClick={() => {
                    setBarcodeType(t.value);
                    setText(t.example);
                  }}
                  className={cn(
                    "px-4 py-3 rounded-xl text-sm font-semibold border transition-all duration-200 text-left flex flex-col gap-1",
                    barcodeType === t.value
                      ? "bg-rose-500/20 border-rose-500/50 text-rose-300 ring-1 ring-rose-500/30"
                      : "bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700 hover:text-zinc-300"
                  )}
                >
                  <span className={cn(
                    "text-sm",
                    barcodeType === t.value ? "text-rose-300" : "text-zinc-200"
                  )}>{t.label}</span>
                  <span className="text-[10px] leading-tight text-zinc-500 opacity-80 font-normal">
                    {t.description}
                  </span>
                </button>
              ))}
            </div>
          </div>

          <Separator className="bg-zinc-800/50" />

          {/* Text input */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <Label className="text-zinc-300 text-xs font-bold uppercase tracking-wider">Text Data</Label>
              <button
                onClick={copyText}
                className="text-[10px] flex items-center gap-1 text-zinc-500 hover:text-zinc-300 transition-colors"
              >
                {copied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                {copied ? "Copied" : "Copy Sample"}
              </button>
            </div>
            <div className="relative">
              <input
                type="text"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Enter content..."
                className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3.5 text-zinc-100 text-sm focus:outline-none focus:ring-2 focus:ring-rose-500/40 transition-shadow transition-colors"
              />
              {selectedType && (
                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                   <Badge variant="outline" className="text-[10px] py-0 h-5 border-zinc-700 text-zinc-500 uppercase">
                    {selectedType.value}
                   </Badge>
                </div>
              )}
            </div>
          </div>

          {/* Controls: Color - 2 Column Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Colors: FG */}
            <div className="space-y-3">
              <Label className="text-zinc-300 text-[10px] font-bold uppercase tracking-widest pl-1">Foreground</Label>
              <div className="flex items-center gap-2 p-1.5 bg-zinc-900 border border-zinc-800 rounded-xl h-12">
                <input
                  type="color"
                  value={fgColor}
                  onChange={(e) => setFgColor(e.target.value)}
                  className="w-8 h-full rounded-lg overflow-hidden border-0 bg-transparent cursor-pointer"
                />
                <input
                  type="text"
                  value={fgColor}
                  onChange={(e) => setFgColor(e.target.value)}
                  className="flex-1 bg-transparent text-zinc-300 text-[11px] font-mono focus:outline-none uppercase"
                />
              </div>
            </div>

            {/* Colors: BG */}
            <div className="space-y-3">
              <Label className="text-zinc-300 text-[10px] font-bold uppercase tracking-widest pl-1">Background</Label>
              <div className="flex items-center gap-2 p-1.5 bg-zinc-900 border border-zinc-800 rounded-xl h-12">
                <input
                  type="color"
                  value={bgColor}
                  onChange={(e) => setBgColor(e.target.value)}
                  className="w-8 h-full rounded-lg overflow-hidden border-0 bg-transparent cursor-pointer"
                />
                <input
                  type="text"
                  value={bgColor}
                  onChange={(e) => setBgColor(e.target.value)}
                  className="flex-1 bg-transparent text-zinc-300 text-[11px] font-mono focus:outline-none uppercase"
                />
              </div>
            </div>
          </div>

          {/* Color Presets */}
          <div className="space-y-3">
            <Label className="text-zinc-300 text-[10px] font-bold uppercase tracking-widest pl-1">Color Presets</Label>
            <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
              {COLOR_PRESETS.map((p) => (
                <button
                  key={p.name}
                  onClick={() => {
                    setFgColor(p.fg);
                    setBgColor(p.bg);
                  }}
                  className="flex flex-col items-center gap-1.5 p-2 rounded-xl bg-zinc-900 border border-zinc-800 hover:border-zinc-700 transition-all group"
                >
                  <div className="w-full h-4 rounded-full flex overflow-hidden ring-1 ring-zinc-800 shadow-inner">
                    <div style={{ backgroundColor: p.fg }} className="w-1/2 h-full" />
                    <div style={{ backgroundColor: p.bg }} className="w-1/2 h-full" />
                  </div>
                  <span className="text-[9px] text-zinc-500 group-hover:text-zinc-300 transition-colors uppercase font-bold">{p.name}</span>
                </button>
              ))}
            </div>
          </div>

          {error && (
            <div className="flex items-start gap-2 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-xl px-4 py-3 text-sm">
              <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          )}

          {/* Action Buttons */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 pt-2">
            <Button
              onClick={handleCopyPng}
              disabled={!!error || !text.trim()}
              variant="outline"
              className="h-12 border-zinc-800 hover:bg-zinc-800 text-zinc-300 rounded-xl font-bold gap-2 transition-all active:scale-[0.98]"
            >
              {pngCopied ? <Check className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4 text-rose-400" />}
              {pngCopied ? "Copied" : "Copy Image"}
            </Button>
            <Button
              onClick={handleDownloadPng}
              disabled={!!error || !text.trim()}
              variant="outline"
              className="h-12 border-zinc-800 hover:bg-zinc-800 text-zinc-400 rounded-xl font-bold gap-2 transition-all active:scale-[0.98]"
            >
              <Download className="w-4 h-4" />
              Save PNG
            </Button>
            <Button
              onClick={handleDownloadSvg}
              disabled={!!error || !text.trim()}
              className="h-12 bg-rose-600 hover:bg-rose-500 text-white rounded-xl font-bold gap-2 shadow-lg shadow-rose-900/20 transition-all active:scale-[0.98] sm:col-span-1"
            >
              <Download className="w-4 h-4" />
              Save SVG
            </Button>
          </div>
        </div>

        {/* Preview Area - 5 cols */}
        <div className="xl:col-span-5 flex flex-col items-center gap-6 pt-7">
          <div className="w-full aspect-square flex flex-col items-center justify-center rounded-[2rem] bg-zinc-900/40 border border-zinc-800/60 p-12 shadow-2xl relative overflow-hidden group">
            <div className="absolute inset-0 bg-gradient-to-br from-rose-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

            {!text.trim() || error ? (
              <div className="flex flex-col items-center gap-3 text-zinc-800">
                <div className="p-6 rounded-3xl bg-zinc-900/80 border border-zinc-800 shadow-inner">
                  <Barcode className="w-12 h-12" />
                </div>
                <p className="text-[10px] font-black uppercase tracking-[0.2em]">{error ? "ERROR" : "Waiting"}</p>
              </div>
            ) : (
              <div className="relative z-10 w-full h-full flex items-center justify-center transition-all duration-500 group-hover:scale-[1.03]">
                <canvas
                  ref={canvasRef}
                  className="max-w-full max-h-full rounded-xl shadow-2xl"
                  style={{ 
                    imageRendering: "pixelated",
                    boxShadow: `0 30px 60px -12px ${fgColor}25`
                  }}
                />
              </div>
            )}
          </div>

          {!error && text.trim() && (
            <div className="text-center space-y-2">
              <Badge variant="outline" className="bg-zinc-900/50 text-zinc-500 border-zinc-800 px-3 py-1 text-[10px] tracking-wider uppercase">
                {selectedType?.label}
              </Badge>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useCallback, useRef, useEffect } from "react";
import { 
  FileText, 
  UploadCloud, 
  Download, 
  Scissors, 
  FilePlus2, 
  FileImage, 
  X, 
  AlertCircle, 
  Loader2, 
  GripVertical,
  CheckCircle2,
  ArrowRight,
  Copy,
  Check
} from "lucide-react";
import { PDFDocument } from "pdf-lib";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Slider } from "@/components/ui/slider";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";

const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

interface MergeFile {
  id: string;
  file: File;
  pageCount: number;
}

interface PageImage {
  page: number;
  dataUrl: string;
}

export default function PdfEditPage() {
  const [activeTab, setActiveTab] = useState("split");
  const [error, setError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // --- Split State ---
  const [splitFile, setSplitFile] = useState<File | null>(null);
  const [splitPageCount, setSplitPageCount] = useState(0);
  const [splitRanges, setSplitRanges] = useState("");
  const [splitResults, setSplitResults] = useState<{ name: string; url: string }[]>([]);
  const splitInputRef = useRef<HTMLInputElement>(null);

  // --- Merge State ---
  const [mergeFiles, setMergeFiles] = useState<MergeFile[]>([]);
  const [mergeResultUrl, setMergeResultUrl] = useState<string | null>(null);
  const mergeInputRef = useRef<HTMLInputElement>(null);
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  // --- Image State ---
  const [imgFile, setImgFile] = useState<File | null>(null);
  const [imgPageCount, setImgPageCount] = useState(0);
  const [imgScale, setImgScale] = useState(2);
  const [imgResults, setImgResults] = useState<PageImage[]>([]);
  const [copiedPage, setCopiedPage] = useState<number | null>(null);
  const imgInputRef = useRef<HTMLInputElement>(null);

  // Helper: File Size Check
  const validateFileSize = (file: File) => {
    if (file.size > MAX_FILE_SIZE) {
      setError(`File size too large (Max 100MB). Selected file: ${(file.size / 1024 / 1024).toFixed(1)}MB`);
      return false;
    }
    return true;
  };

  // --- Split Logic ---
  const loadSplitFile = async (f: File) => {
    if (f.type !== "application/pdf") return setError("Please select a valid PDF file.");
    if (!validateFileSize(f)) return;
    setError(null);
    setSplitResults([]);
    setSplitFile(f);
    try {
      const buf = await f.arrayBuffer();
      const doc = await PDFDocument.load(buf);
      setSplitPageCount(doc.getPageCount());
      setSplitRanges(`1-${doc.getPageCount()}`);
    } catch {
      setError("Failed to load PDF.");
      setSplitFile(null);
    }
  };

  const handleSplit = async () => {
    if (!splitFile || !splitRanges.trim()) return;
    setError(null);
    const parsed = parseRanges(splitRanges, splitPageCount);
    if (!parsed) {
      setError(`Invalid range format. Example: "1-3, 5, 7-10"`);
      return;
    }
    setIsProcessing(true);
    setProgress(0);
    try {
      const srcBuf = await splitFile.arrayBuffer();
      const srcDoc = await PDFDocument.load(srcBuf);
      const newResults: { name: string; url: string }[] = [];
      for (let i = 0; i < parsed.length; i++) {
        const pages = parsed[i];
        const newDoc = await PDFDocument.create();
        const copied = await newDoc.copyPages(srcDoc, pages);
        copied.forEach((p) => newDoc.addPage(p));
        const bytes = await newDoc.save();
        const blob = new Blob([bytes as any], { type: "application/pdf" });
        const url = URL.createObjectURL(blob);
        const label = pages.length === 1 ? `p${pages[0] + 1}` : `p${pages[0] + 1}-${pages[pages.length - 1] + 1}`;
        newResults.push({ name: `split_${label}.pdf`, url });
        setProgress(Math.round(((i + 1) / parsed.length) * 100));
      }
      setSplitResults(newResults);
    } catch {
      setError("An error occurred during PDF splitting.");
    } finally {
      setIsProcessing(false);
    }
  };

  const parseRanges = (str: string, total: number): number[][] | null => {
    const parts = str.split(",").map(p => p.trim());
    const res: number[][] = [];
    for (const p of parts) {
      if (!p) continue;
      if (p.includes("-")) {
        const [a, b] = p.split("-").map(Number);
        if (isNaN(a) || isNaN(b) || a < 1 || b > total || a > b) return null;
        res.push(Array.from({ length: b - a + 1 }, (_, i) => a - 1 + i));
      } else {
        const n = Number(p);
        if (isNaN(n) || n < 1 || n > total) return null;
        res.push([n - 1]);
      }
    }
    return res.length ? res : null;
  };

  // --- Merge Logic ---
  const addMergeFiles = async (newFiles: File[]) => {
    setError(null);
    setMergeResultUrl(null);
    const pdfs = newFiles.filter(f => f.type === "application/pdf");
    for (const f of pdfs) {
      if (!validateFileSize(f)) continue;
      try {
        const buf = await f.arrayBuffer();
        const doc = await PDFDocument.load(buf);
        setMergeFiles(prev => [...prev, { id: crypto.randomUUID(), file: f, pageCount: doc.getPageCount() }]);
      } catch {
        setError(`Failed to load "${f.name}".`);
      }
    }
  };

  const handleMerge = async () => {
    if (mergeFiles.length < 2) return setError("At least 2 PDFs are required to merge.");
    setError(null);
    setIsProcessing(true);
    setProgress(0);
    try {
      const mergedDoc = await PDFDocument.create();
      for (let i = 0; i < mergeFiles.length; i++) {
        const buf = await mergeFiles[i].file.arrayBuffer();
        const doc = await PDFDocument.load(buf);
        const pages = await mergedDoc.copyPages(doc, doc.getPageIndices());
        pages.forEach(p => mergedDoc.addPage(p));
        setProgress(Math.round(((i + 1) / mergeFiles.length) * 90));
      }
      const bytes = await mergedDoc.save();
      setMergeResultUrl(URL.createObjectURL(new Blob([bytes as any], { type: "application/pdf" })));
      setProgress(100);
    } catch {
      setError("An error occurred during PDF merging.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null) {
      const re = [...mergeFiles];
      const [remed] = re.splice(dragItem.current, 1);
      re.splice(dragOverItem.current, 0, remed);
      setMergeFiles(re);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  // --- Image Logic ---
